# Dependency Management Script

"""
This script assists in managing Python dependency lock files. It can generate
and update requirements.txt files with hashes or manage Poetry lock files for
consistent dependency versions across development and production environments.
"""

import subprocess
import os

def generate_requirements_txt():
    """
    Generate a requirements.txt file with hashes for dependencies.
    """
    subprocess.run(['pip-compile', '--generate-hashes', '--output-file=requirements.txt', 'requirements.in'], check=True)

def update_requirements_txt():
    """
    Update the requirements.txt file to the latest compatible versions.
    """
    subprocess.run(['pip-compile', '--generate-hashes', '-U', '--output-file=requirements.txt', 'requirements.in'], check=True)

def install_dependencies():
    """
    Install dependencies from the requirements.txt file.
    """
    subprocess.run(['pip', 'install', '-r', 'requirements.txt'], check=True)

def manage_poetry_dependencies(update=False):
    """
    Manage dependencies with Poetry.

    Args:
        update (bool): If True, will update dependencies to latest compatible versions.
    """
    if update:
        subprocess.run(['poetry', 'update'], check=True)
    else:
        subprocess.run(['poetry', 'install'], check=True)

def main():
    """
    Main entry point for the script. Allows management of dependencies.
    """
    action = input("Choose an action: [generate|update|install|manage_poetry] ").strip().lower()

    if action == 'generate':
        generate_requirements_txt()
        print("Generated requirements.txt with hashes.")
    elif action == 'update':
        update_requirements_txt()
        print("Updated requirements.txt to latest versions.")
    elif action == 'install':
        install_dependencies()
        print("Installed dependencies from requirements.txt.")
    elif action == 'manage_poetry':
        update = input("Update dependencies? (yes/no) ").strip().lower() == 'yes'
        manage_poetry_dependencies(update)
        if update:
            print("Updated Poetry dependencies.")
        else:
            print("Installed Poetry dependencies.")
    else:
        print("Invalid action. Please choose from the listed options.")

if __name__ == "__main__":
    main()